import React, { useState, useEffect, useRef } from "react";
import { Link, useNavigate, useLocation } from "react-router-dom";
import { 
  FaHome, 
  FaGraduationCap, 
  FaUpload, 
  FaInfoCircle, 
  FaSignInAlt, 
  FaUserPlus, 
  FaBars, 
  FaTimes,
  FaBook,
  FaUserCircle,
  FaSearch,
  FaChevronDown,
  FaChevronRight,
  FaBell,
  FaDownload
} from "react-icons/fa";
import "./Navbar.css";

const Navbar = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const [isCoursesOpen, setIsCoursesOpen] = useState(false);
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [userName, setUserName] = useState("");
  const [searchQuery, setSearchQuery] = useState("");
  const [notificationCount] = useState(3);
  
  const dropdownRef = useRef(null);
  const userMenuRef = useRef(null);
  const navigate = useNavigate();
  const location = useLocation();

  // Check login status on mount and when location changes
  useEffect(() => {
    const token = localStorage.getItem('study_portal_token');
    const user = localStorage.getItem('study_portal_user');
    
    if (token && user) {
      setIsLoggedIn(true);
      try {
        const userData = JSON.parse(user);
        setUserName(userData.name || userData.email || 'User');
      } catch {
        setUserName('User');
      }
    } else {
      setIsLoggedIn(false);
      setUserName('');
    }
  }, [location]);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 10);
    };
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  // Close dropdowns when clicking outside
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        setIsCoursesOpen(false);
      }
      if (userMenuRef.current && !userMenuRef.current.contains(event.target)) {
        setIsUserMenuOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Close mobile menu on route change
  useEffect(() => {
    setIsMenuOpen(false);
    setIsCoursesOpen(false);
    setIsUserMenuOpen(false);
  }, [location]);

  const handleSearch = (e) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      navigate(`/search?q=${encodeURIComponent(searchQuery)}`);
      setSearchQuery('');
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('study_portal_token');
    localStorage.removeItem('study_portal_user');
    setIsLoggedIn(false);
    setUserName('');
    setIsUserMenuOpen(false);
    navigate('/');
  };

  // COURSES DATA - Add proper paths
  const courses = [
    { 
      id: 1,
      name: "B.Tech", 
      icon: "💻", 
      path: "/courses/btech", 
      description: "Engineering", 
      color: "#4f46e5",
      duration: "4 Years",
      semester: "1-8"
    },
    { 
      id: 2,
      name: "BCA", 
      icon: "📱", 
      path: "/courses/bca", 
      description: "Computer Applications", 
      color: "#ec4899",
      duration: "3 Years",
      semester: "1-6"
    },
    { 
      id: 3,
      name: "BBA", 
      icon: "📊", 
      path: "/courses/bba", 
      description: "Business Admin", 
      color: "#10b981",
      duration: "3 Years",
      semester: "1-6"
    },
    { 
      id: 4,
      name: "MBA", 
      icon: "💼", 
      path: "/courses/mba", 
      description: "Management", 
      color: "#f59e0b",
      duration: "2 Years",
      semester: "1-4"
    },
    { 
      id: 5,
      name: "MCA", 
      icon: "🎯", 
      path: "/courses/mca", 
      description: "Computer Applications", 
      color: "#8b5cf6",
      duration: "2 Years",
      semester: "1-4"
    },
    { 
      id: 6,
      name: "B.Sc", 
      icon: "🔬", 
      path: "/courses/bsc", 
      description: "Science", 
      color: "#06b6d4",
      duration: "3 Years",
      semester: "1-6"
    },
    { 
      id: 7,
      name: "B.Com", 
      icon: "📈", 
      path: "/courses/bcom", 
      description: "Commerce", 
      color: "#14b8a6",
      duration: "3 Years",
      semester: "1-6"
    },
    { 
      id: 8,
      name: "BA", 
      icon: "📖", 
      path: "/courses/ba", 
      description: "Arts", 
      color: "#f97316",
      duration: "3 Years",
      semester: "1-6"
    },
  ];

  // Handle course click with navigation
  const handleCourseClick = (coursePath, e) => {
    e.preventDefault();
    e.stopPropagation();
    console.log('Navigating to:', coursePath); // Debug log
    navigate(coursePath);
    setIsCoursesOpen(false);
    setIsMenuOpen(false);
  };

  return (
    <nav className={`navbar ${isScrolled ? "scrolled" : ""}`}>
      <div className="nav-container">
        
        {/* Logo */}
        <Link to="/" className="logo" onClick={() => setIsCoursesOpen(false)}>
          <div className="logo-icon">📚</div>
          <div className="logo-text">
            <span className="logo-title">Study Portal</span>
            <span className="logo-subtitle">by Karan</span>
          </div>
        </Link>

        {/* Desktop Menu */}
        <div className="desktop-nav">
          <Link to="/" className={`nav-link ${location.pathname === '/' ? 'active' : ''}`}>
            <FaHome className="nav-icon" /> 
            <span>Home</span>
          </Link>

          {/* Courses Dropdown - FIXED */}
          <div className="dropdown-wrapper" ref={dropdownRef}>
            <div 
              className={`nav-link ${location.pathname.includes('/courses') ? 'active' : ''}`}
              onClick={() => setIsCoursesOpen(!isCoursesOpen)}
            >
              <FaGraduationCap className="nav-icon" /> 
              <span>Courses</span>
              <FaChevronDown className={`dropdown-arrow ${isCoursesOpen ? 'rotated' : ''}`} />
            </div>
            
            <div className={`dropdown-content ${isCoursesOpen ? 'show' : ''}`}>
              <div className="dropdown-header">
                <h4>Popular Courses</h4>
                <Link to="/courses" className="view-all-link" onClick={() => setIsCoursesOpen(false)}>
                  View All →
                </Link>
              </div>
              
              <div className="dropdown-grid">
                {courses.map((course) => (
                  <div 
                    key={course.id} 
                    className="dropdown-item-wrapper"
                    onClick={(e) => handleCourseClick(course.path, e)}
                  >
                    <div 
                      className="dropdown-item"
                      style={{ '--course-color': course.color }}
                    >
                      <span className="course-icon" style={{ background: `${course.color}20` }}>
                        {course.icon}
                      </span>
                      <div className="course-info">
                        <div className="course-name">{course.name}</div>
                        <div className="course-desc">{course.description}</div>
                        <div className="course-meta">
                          <span className="course-duration">{course.duration}</span>
                          <span className="course-semester">{course.semester}</span>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>

              <div className="dropdown-footer">
                <Link to="/courses" className="footer-link" onClick={() => setIsCoursesOpen(false)}>
                  Browse All Courses <span className="arrow">→</span>
                </Link>
              </div>
            </div>
          </div>

          {/* Upload Link */}
          <Link to="/upload" className={`nav-link ${location.pathname === '/upload' ? 'active' : ''}`}>
            <FaUpload className="nav-icon" /> Upload
          </Link>
          
          {/* About Link */}
          <Link to="/about" className={`nav-link ${location.pathname === '/about' ? 'active' : ''}`}>
            <FaInfoCircle className="nav-icon" /> About
          </Link>

          {/* Search Bar */}
          <form onSubmit={handleSearch} className="search-wrapper">
            <input 
              type="text" 
              placeholder="Search courses..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
            <button type="submit" className="search-btn">
              <FaSearch />
            </button>
          </form>

          {/* Notifications */}
          {isLoggedIn && (
            <div className="notification-wrapper">
              <button className="notification-btn">
                <FaBell />
                {notificationCount > 0 && (
                  <span className="notification-badge">{notificationCount}</span>
                )}
              </button>
            </div>
          )}

          {/* Auth Buttons / User Menu */}
          <div className="auth-section">
            {isLoggedIn ? (
              <div className="user-menu-wrapper" ref={userMenuRef}>
                <button 
                  className="user-menu-btn"
                  onClick={() => setIsUserMenuOpen(!isUserMenuOpen)}
                >
                  <FaUserCircle className="user-icon" />
                  <span className="user-name">{userName}</span>
                  <FaChevronDown className={`dropdown-arrow ${isUserMenuOpen ? 'rotated' : ''}`} />
                </button>

                {isUserMenuOpen && (
                  <div className="user-dropdown">
                    <div className="user-dropdown-header">
                      <FaUserCircle className="user-avatar" />
                      <div>
                        <div className="user-fullname">{userName}</div>
                        <div className="user-email">student@example.com</div>
                      </div>
                    </div>
                    
                    <div className="user-dropdown-links">
                      <Link to="/profile" className="user-dropdown-link" onClick={() => setIsUserMenuOpen(false)}>
                        <FaUserCircle /> My Profile
                      </Link>
                      <Link to="/downloads" className="user-dropdown-link" onClick={() => setIsUserMenuOpen(false)}>
                        <FaDownload /> My Downloads
                      </Link>
                    </div>

                    <div className="user-dropdown-footer">
                      <button onClick={handleLogout} className="logout-btn">
                        <FaSignInAlt /> Logout
                      </button>
                    </div>
                  </div>
                )}
              </div>
            ) : (
              <>
                <button onClick={() => navigate("/login")} className="auth-btn login-btn">
                  <FaSignInAlt /> Login
                </button>
                <button onClick={() => navigate("/register")} className="auth-btn register-btn">
                  <FaUserPlus /> Register
                </button>
              </>
            )}
          </div>
        </div>

        {/* Mobile Menu Button */}
        <button className="mobile-menu-btn" onClick={() => setIsMenuOpen(!isMenuOpen)}>
          {isMenuOpen ? <FaTimes /> : <FaBars />}
        </button>
      </div>

      {/* Mobile Menu */}
      <div className={`mobile-nav ${isMenuOpen ? "open" : ""}`}>
        <div className="mobile-nav-header">
          <div className="mobile-logo">
            <span className="logo-icon-small">📚</span>
            <h3>Study Portal</h3>
          </div>
          <button className="close-menu-btn" onClick={() => setIsMenuOpen(false)}>
            <FaTimes />
          </button>
        </div>

        {/* Mobile User Info */}
        {isLoggedIn && (
          <div className="mobile-user-info">
            <FaUserCircle className="mobile-user-avatar" />
            <div>
              <div className="mobile-user-name">{userName}</div>
              <div className="mobile-user-email">student@example.com</div>
            </div>
          </div>
        )}

        <div className="mobile-nav-links">
          <Link to="/" className="mobile-nav-link" onClick={() => setIsMenuOpen(false)}>
            <FaHome /> Home
          </Link>

          {/* Mobile Courses Section */}
          <div className="mobile-dropdown">
            <div 
              className="mobile-nav-link mobile-dropdown-trigger"
              onClick={() => setIsCoursesOpen(!isCoursesOpen)}
            >
              <FaGraduationCap /> Courses
              <FaChevronRight className={`mobile-arrow ${isCoursesOpen ? 'rotated' : ''}`} />
            </div>
            <div className={`mobile-dropdown-content ${isCoursesOpen ? 'show' : ''}`}>
              {courses.map((course) => (
                <div
                  key={course.id}
                  className="mobile-dropdown-item-wrapper"
                  onClick={(e) => {
                    handleCourseClick(course.path, e);
                    setIsMenuOpen(false);
                  }}
                >
                  <div className="mobile-dropdown-item">
                    <span className="mobile-course-icon">{course.icon}</span>
                    <div>
                      <div className="mobile-course-name">{course.name}</div>
                      <div className="mobile-course-desc">{course.description}</div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <Link to="/upload" className="mobile-nav-link" onClick={() => setIsMenuOpen(false)}>
            <FaUpload /> Upload
          </Link>
          <Link to="/about" className="mobile-nav-link" onClick={() => setIsMenuOpen(false)}>
            <FaInfoCircle /> About
          </Link>

          {/* Mobile Search */}
          <div className="mobile-search">
            <form onSubmit={(e) => {
              e.preventDefault();
              if (searchQuery.trim()) {
                navigate(`/search?q=${encodeURIComponent(searchQuery)}`);
                setSearchQuery('');
                setIsMenuOpen(false);
              }
            }}>
              <input 
                type="text" 
                placeholder="Search courses..." 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
              <button type="submit" className="mobile-search-btn">
                <FaSearch />
              </button>
            </form>
          </div>

          {/* Mobile Auth */}
          <div className="mobile-auth">
            {isLoggedIn ? (
              <>
                <Link to="/profile" className="mobile-auth-link" onClick={() => setIsMenuOpen(false)}>
                  <FaUserCircle /> Profile
                </Link>
                <button onClick={handleLogout} className="mobile-auth-btn logout">
                  <FaSignInAlt /> Logout
                </button>
              </>
            ) : (
              <>
                <button 
                  onClick={() => { 
                    navigate("/login"); 
                    setIsMenuOpen(false); 
                  }} 
                  className="mobile-auth-btn login"
                >
                  <FaSignInAlt /> Login
                </button>
                <button 
                  onClick={() => { 
                    navigate("/register"); 
                    setIsMenuOpen(false); 
                  }} 
                  className="mobile-auth-btn register"
                >
                  <FaUserPlus /> Register
                </button>
              </>
            )}
          </div>
        </div>

        <div className="mobile-nav-footer">
          <p>© 2024 Study Portal by Karan</p>
        </div>
      </div>

      {isMenuOpen && <div className="mobile-overlay" onClick={() => setIsMenuOpen(false)}></div>}
    </nav>
  );
};

export default Navbar;
